Field.js-content:
var bu = tsu.getBusiUnit();
        var TxSts = tsu.getValue("/Document/Ack/TxSts","Sts"); 
        var AckdMsgRef = tsu.getValue("Document/Ack/AckdMsgRef","Id");
        tsu.writeLog("TxSts_001: ="+TxSts[0]);
        var Type = tsu.getPartValue(AckdMsgRef[0],1,3);
        tsu.writeLog("AckdMsgRef_001: ="+AckdMsgRef[0]);
        if(TxSts[0] == "PROP")
        {
          tsu.writeLog("TxSts_001_PROP: ="+TxSts[0]);
          var TrxRef = tsu.getValue("/Document/Ack/UsrTxRef","Id");
	     tsu.writeLog("TrxRef1111: ="+TrxRef);
          tsu.setHashMap("C_TRX_REF",TrxRef);
        }
        //manage the 001 message after 014 in OCBC mode
        var OCBC = tsu.getPartValue(AckdMsgRef[0],1,4);
        var DS1 = tsu.getPartValue(AckdMsgRef[0],13,2);
        if(OCBC=="OCBC" && DS1== "DS")
        {
           tsu.writeLog("TxSts_001_ACTV: ="+TxSts[0]);
		   var MSGID = tsu.getValue("/Document/Ack/AckdMsgRef","Id");
           tsu.writeLog("MSGIDddddd: ="+MSGID[0]); 

           var fld_list  = tsu.addFieldList(null,"C_TRX_REF");
           var sql_condition = tsu.addSQLCondition(null,"C_MSG_ID",AckdMsgRef[0]);
           sql_condition = tsu.addSQLCondition(sql_condition,"C_UNIT_CODE",bu);
           var result   = tsu.executeQuery("EXIMSYS.TSU_MSGS",fld_list,sql_condition);
           var TrxRef= tsu.getDBFieldValue(result,"C_TRX_REF");
           tsu.writeLog("TrxRef ="+TrxRef);
           tsu.setHashMap("C_TRX_REF",TrxRef);
           tsu.setHashMap("C_MSG_TYPE","tsmt.001.001.03(014)");
        }

       if(Type == "ARS" )
        {
           tsu.writeLog("TxSts_001_TYPE: ="+Type);
           var MSGID = tsu.getValue("/Document/Ack/AckdMsgRef","Id");
           tsu.writeLog("MSGIDddddd: ="+MSGID[0]); 

           var fld_list  = tsu.addFieldList(null,"C_TRX_REF");
           var sql_condition = tsu.addSQLCondition(null,"C_MSG_ID",AckdMsgRef[0]);
           sql_condition = tsu.addSQLCondition(sql_condition,"C_UNIT_CODE",bu);
           var result   = tsu.executeQuery("EXIMSYS.TSU_MSGS",fld_list,sql_condition);
           var TrxRef= tsu.getDBFieldValue(result,"C_TRX_REF");
           tsu.writeLog("TrxRef ="+TrxRef);
           tsu.setHashMap("C_TRX_REF",TrxRef);
        }

        //manage the 001 message after 044,014 -S
        var DS = tsu.getPartValue(AckdMsgRef[0],9,2);
        var PAY = tsu.getPartValue(AckdMsgRef[0],9,3);
        if(DS=="DS" || PAY=="PAY")
        {
        	tsu.setHashMap("C_MSG_TYPE","tsmt.001.001.03(014)");
        }
